member.remarks:
Example request:
{
  "deploymentName": "gpt-4-turbo-deployment",
  "message": "Which beginner-friendly sunny balcony plants are in stock, and how should I care for them?",
  "temperature": 0.2,
  "maxTokens": 300
}

Example response:
{
  "answer": "Lavender and geranium are in stock and suitable for sunny balconies. Water deeply but infrequently.",
  "sources": [
    { "kind": "structured", "source": "Products", "itemId": "1", "score": 1.0 },
    { "kind": "unstructured", "source": "plant-care.md", "itemId": "plant-care.md#chunk-1", "score": 0.89 }
  ]
}

Example tool-enabled request:
{
  "deploymentName": "gpt-4-turbo-deployment",
  "messages": [
    { "role": "user", "content": "Find beginner plants for a sunny balcony." }
  ],
  "temperature": 0.4,
  "maxTokens": 200,
  "tools": [
    {
      "type": "function",
      "function": {
        "name": "SearchProducts",
        "description": "Search products by catalog filters",
        "parameters": {
          "type": "object",
          "properties": { "category": { "type": "string" } },
          "required": ["category"]
        }
      }
    }
  ],
  "toolChoice": "auto",
  "parallelToolCalls": true
}

Example request:
{
  "query": "Do you offer home delivery?",
  "topK": 3
}
